Greedy insertion with fallback seed assignment using cost-aware candidate evaluation across all existing routes plus potential new vehicles.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const SEED_INDEX = 0
	type cand struct {
		assignIdx int
		delta     float64
		ok        bool
	}
	for shipIdx := range oris {
		bestCand := cand{-1, 1e18, false}
		evalOrder := make([]int, dispatch.AssignsLen+1)
		for i := 0; i <= dispatch.AssignsLen; i++ {
			evalOrder[i] = i
		}
		for _, assignIdx := range evalOrder {
			if assignIdx >= MAXASSIGNS {
				continue
			}
			prevCost := dispatch.Assigns[assignIdx].Cost
			added := dispatch.Assigns[assignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if added {
				dispatch.Assigns[assignIdx].GenRoute()
				newCost := dispatch.Assigns[assignIdx].Cost
				if newCost >= 0 {
					delta := newCost - prevCost
					if delta < bestCand.delta {
						bestCand.assignIdx = assignIdx
						bestCand.delta = delta
						bestCand.ok = true
					}
					dispatch.Assigns[assignIdx].RemoveShip(total_ship + shipIdx)
					dispatch.Assigns[assignIdx].GenRoute()
				} else {
					dispatch.Assigns[assignIdx].RemoveShip(total_ship + shipIdx)
					dispatch.Assigns[assignIdx].GenRoute()
				}
			}
		}
		inserted := false
		targetIdx := bestCand.assignIdx
		if bestCand.ok && targetIdx >= 0 && targetIdx < MAXASSIGNS {
			added := dispatch.Assigns[targetIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if added {
				dispatch.Assigns[targetIdx].GenRoute()
				if dispatch.Assigns[targetIdx].Cost >= 0 {
					inserted = true
					if targetIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = targetIdx + 1
					}
				} else {
					dispatch.Assigns[targetIdx].RemoveShip(total_ship + shipIdx)
					dispatch.Assigns[targetIdx].GenRoute()
					inserted = false
				}
			}
		}
		if !inserted {
			fallbackIdx := SEED_INDEX
			if dispatch.AssignsLen < MAXASSIGNS {
				fallbackIdx = dispatch.AssignsLen
			}
			if fallbackIdx < MAXASSIGNS {
				added := dispatch.Assigns[fallbackIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
				if added {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						if fallbackIdx >= dispatch.AssignsLen {
							dispatch.AssignsLen = fallbackIdx + 1
						}
					} else {
						dispatch.Assigns[fallbackIdx].RemoveShip(total_ship + shipIdx)
						dispatch.Assigns[fallbackIdx].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

